import fs from "node:fs/promises";
import path from "node:path";
import { loadReleaseConfig, resolveProfileConfig } from "./release-config.mjs";

const profileName = process.argv[2];

if (!profileName) {
  throw new Error("Usage: node ./scripts/write-release-tauri-properties.mjs <preview|production-candidate>");
}

const config = await loadReleaseConfig();
const profile = resolveProfileConfig(config, profileName);

const tauriPropertiesPath = path.join(config.packageRoot, "android", "app", "tauri.properties");
const content = [
  "// THIS FILE IS GENERATED BY packages/vibe-app-tauri/scripts/write-release-tauri-properties.mjs",
  `tauri.android.versionName=${profile.packageVersion}${profile.androidVersionNameSuffix}`,
  `tauri.android.versionCode=${profile.androidVersionCode}`,
  `vibe.release.applicationId=${profile.androidApplicationId}`,
  `vibe.release.namespace=${profile.androidApplicationId}`,
  `vibe.release.appName=${profile.androidAppName}`,
  `vibe.release.deepLinkScheme=${profile.deepLinkScheme}`,
  `vibe.release.updaterChannel=${profile.updaterChannel}`,
].join("\n");

await fs.writeFile(tauriPropertiesPath, `${content}\n`, "utf8");
console.log(`Wrote ${tauriPropertiesPath} for ${profileName}`);
